51: // UnmarshalYAML implements the yaml.Unmarshaler interface for URLs.
52: func (u *URL) UnmarshalYAML(unmarshal func(interface{}) error) error {
53: 	var s string
54: 	if err := unmarshal(&s); err != nil {
55: 		return err
56: 	}
57: 
58: 	urlp, err := url.Parse(s)
59: 	if err != nil {
60: 		return err
61: 	}
62: 	u.URL = urlp
63: 	return nil
64: }
65: 
66: // MarshalYAML implements the yaml.Marshaler interface for URLs.
67: func (u URL) MarshalYAML() (interface{}, error) {
68: 	if u.URL != nil {
69: 		return u.String(), nil
70: 	}
71: 	return nil, nil
72: }
